python -c "
from outlines.prompts import prompt, register_filter, unregister_filter

register_filter('shout', str.upper)

@prompt
def greet(name):
    '{{ name | shout }}'

print(greet('world'))

unregister_filter('shout')

@prompt
def greet2(name):
    '{{ name | shout }}'

try:
    greet2('world2')
    print('ERROR: should have failed')
except Exception as e:
    print('OK, unregistered, new template fails as expected:', type(e).__name__)

# check local filters (built-in) take precedence over a same-named global filter
register_filter('name', lambda x: 'overridden')
@prompt
def check_precedence(fn):
    '{{ fn | name }}'

def my_func(): pass
print(check_precedence(my_func))
"

